import { useState } from 'react';
import axios from 'axios';

const Quiz = ({ docId }) => {
  const [quiz, setQuiz] = useState('');

  const handleGenerateQuiz = async () => {
    const token = localStorage.getItem('token');
    const res = await axios.get(`http://localhost:5000/api/documents/${docId}/quiz`, { headers: { Authorization: `Bearer ${token}` } });
    setQuiz(res.data.quiz);
  };

  return (
    <div className="mt-4">
      <button onClick={handleGenerateQuiz} className="bg-yellow-600 text-white p-2">Generate Quiz</button>
      {quiz && <pre className="mt-2">{quiz}</pre>}
    </div>
  );
};

export default Quiz;
